# 1. definizione metodi per il download dei dati

def download_prices(ticker, start_date, end_date):
    data = yf.download(
        ticker,
        start=start_date,
        end=end_date
        )
    return data['Close']

def portfolio_stats(series):
    returns = series.pct_change().dropna()

    cumulative_return = (series.iloc[-1] / series.iloc[0]) - 1
    volatility = returns.std() * np.sqrt(252)
    sharpe = returns.mean() / returns.std() * np.sqrt(252)

    drawdown = series / series.cummax() - 1
    max_dd = drawdown.min()

    return {
        "Return": cumulative_return,
        "Volatility": volatility,
        "Sharpe": sharpe,
        "Max Drawdown": max_dd
    }

def calculate_returns(prices):
    return prices.pct_change().dropna()
def calculate_sharpe_ratio(returns, risk_free_rate=0.01):
    excess_returns = returns - risk_free_rate
    return excess_returns.mean() / excess_returns.std()
def markowitz(returns):

    mean_returns = returns.mean() * 12
    cov_matrix = returns.cov() * 12
    n_assets = len(mean_returns)
    # funzione da minimizzare

    def portfolio_volatility(weights):
        return np.sqrt(weights.T @ cov_matrix @ weights)
    # vincolo: somma dei pesi = 1
    constraints = ({'type': 'eq', 'fun': lambda w: np.sum(w) - 1},)
    # niente short selling
    bounds = tuple((0, 1) for _ in range(n_assets))
    # punto di partenza
    initial_weights = np.ones(n_assets) / n_assets

    result = minimize(portfolio_volatility, initial_weights, method="SLSQP", bounds=bounds, constraints=constraints)

    return pd.Series(result.x, index=returns.columns)

def format_weights(weights):
    weights = weights.copy()

    # elimina rumore numerico
    weights = weights.clip(lower=0)

    # rimuove quasi-zero
    weights = weights[weights > 1e-6]

    # normalizza (importante dopo il clipping)
    weights = weights / weights.sum()

    return weights.round(4)

def format_weights_percent(weights):

    weights = format_weights(weights)
    return (weights * 100).round(2)

def apply_weights_to_returns(returns_test, weights, initial_capital=1):

    """
    returns_test: DataFrame (date × assets)
    weights: Series (assets → weights)
    """

    # allinea colonne (importantissimo)
    returns_test = returns_test[weights.index]

    # calcolo rendimento portfolio giornaliero
    portfolio_returns = returns_test.dot(weights)

    return portfolio_returns

def predict (df, anno_predizione, alpha, coeff):
  last_row = df.iloc[[-1]]
  prediction = (alpha + last_row * coeff).sum().round(2)
  return prediction

