# Scegliamo quanti titoli comprare ogni anno (es. i 3 più forti su 10)
top_n = 3

for anno in range(2012, 2025):

    # 1. DEFINIZIONE DELLE DATE (Lookback di 12 mesi)
    # Guardiamo i prezzi alla fine dell'anno precedente (es. Dicembre 2010 vs Dicembre 2011)
    anno_fine_train = anno - 1
    anno_inizio_train = anno - 2

    # Estraiamo i prezzi di chiusura di quegli anni
    # Usiamo resample('Y').last() per prendere con certezza il prezzo dell'ultimo giorno dell'anno
    prezzo_inizio = prezzi_asset_mensili.loc[str(anno_inizio_train)].resample('YE').last().iloc[-1]
    prezzo_fine = prezzi_asset_mensili.loc[str(anno_fine_train)].resample('YE').last().iloc[-1]

    # 2. CALCOLO DEL MOMENTUM (Il segnale)
    # Calcoliamo il rendimento generato in quei 12 mesi di osservazione
    rendimento_12m = (prezzo_fine / prezzo_inizio) - 1

    # 3. RANKING E ALLOCAZIONE PESI
    # Ordiniamo i titoli dal migliore al peggiore
    titoli_ordinati = rendimento_12m.sort_values(ascending=False)

    # Selezioniamo solo i primi 3 (i vincitori)
    vincitori = titoli_ordinati.head(top_n).index

    # Creiamo un dizionario di pesi: diamo un peso Equipesato (es. 33.3%) ai vincitori, 0 agli altri
    pesi_mom = {ticker: (1.0 / top_n if ticker in vincitori else 0.0) for ticker in tickers}

    # 4. CALCOLO OUT-OF-SAMPLE (L'anno di test)
    # Estraiamo i rendimenti giornalieri dell'anno in corso (es. 2012)
    price_test = prices.loc[str(anno)]
    rendimenti_test = price_test.pct_change().dropna()

    # Moltiplichiamo i rendimenti per i nostri pesi
    pesi_series = pd.Series(pesi_mom)
    rendimenti_portafoglio_mom = (rendimenti_test * pesi_series).sum(axis=1)

    # 5. SALVATAGGIO DATI
    risultati_out_of_sample_mom.append(rendimenti_portafoglio_mom)

    # Salviamo i pesi per la stampa
    diz_pesi = {t: p*100 for t, p in pesi_mom.items()}
    diz_pesi['Anno'] = anno
    storico_pesi_mom.append(diz_pesi)

# ==============================================================================
# ELABORAZIONE FINALE MOMENTUM
# ==============================================================================
